sql:
SELECT DISTINCT locations.city 
FROM locations
INNER JOIN studies ON locations.location_id = studies.location_id;

SELECT p.*
FROM participants p
INNER JOIN researchers r ON p.name = r.name AND p.email = r.email;

external_knowledge:
- 'Data-heavy contributors' refers to researchers who have uploaded more data than the average;
- 'Places' refer to the locations where the research is conducted;
- 'Typical amounts' are the average data sizes uploaded by researchers at each location.
